If I call the function (i.e. scheduled through the scheduler) from another function within the same file, it is able to get access to the global variable.

Example:
mydict = {'a':1}

def foo(myarg):
    ''' Schedule this function'''
   print(mydict)      <<<------ Returns {} when scheduled.  However, prints the value of mydict when called
                               <<<------ from within 'bar()'

def bar():
   foo(1)

Just for completeness:
```
import execjs
import re

def get_js(page):
    S = re.search("S='(\w+)", page).group(1)
    L = len(S)
    U = 0
    A = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    s = {}
    for u in xrange(64):
       s[A[u]] = u

    l = 0
    r = ""
    for i in xrange(L):
       c = s[S[i]];
       U = (U << 6) + c;
       l += 6;
       while l >= 8:
          l -= 8
          a = ( U >> l & 0xff ) or ( i < (L-2))
          r += ''.join(map(unichr, [a]))
    a, b = r.split(";")[0], r.split(";")[1]
    return js_eval((a, b))

def js_eval(js):
    a, b = js
    val = execjs.eval(a)
    key = execjs.eval(b[9:-4])[:-1]
    return key, val
```
