      "attr": {"act_type": "relu"}, 
      "inputs": [[15, 0, 0]]
    }, 
    {
      "op": "FullyConnected", 
      "name": "fullyconnected5", 
      "attr": {"num_hidden": "2"}, 
      "inputs": [[16, 0, 0], [17, 0, 0], [18, 0, 0]]
    }, 
    {
      "op": "Reshape", 
      "name": "reshape1", 
      "attr": {"shape": "(0, 2)"}, 
      "inputs": [[19, 0, 0]]
    }, 
    {
      "op": "transpose", 
      "name": "transpose0", 
      "attr": {"axes": "(1, 0)"}, 
      "inputs": [[20, 0, 0]]
    }, 
    {
      "op": "SoftmaxOutput", 
      "name": "softmax", 
      "inputs": [[22, 0, 0], [23, 0, 0]]
    }
```
So all this layers currently are making use of keyword `attr` while generating the symbol file in MXNet 0.12.0 version. I checked the [_layers.py](https://github.com/apache/incubator-mxnet/blob/master/tools/coreml/converter/_layers.py) in various branches like dev, master, ci-test, mli-patch-1, all the branches for other layers (i.e. transpose, softmax etc) seem to be using `attr` only. I am not getting why you want it to be replaced with `attrs`.

Or else please do let me know if you are referring to some other `attr` which has to be replaced with `attrs`.

